mapper.select:
SELECT name
FROM member
WHERE member_id = #{loginUserId}

SELECT room_id, building, room_number, capacity
FROM lecture_room
WHERE building = #{building}

SELECT
(SELECT COUNT(*) FROM lecture_schedule ls
JOIN lecture l ON ls.lecture_id = l.lecture_id
WHERE ls.room_id = (SELECT room_id FROM lecture_room WHERE room_number = #{roomNumber} LIMIT 1)
AND ls.day_of_week = #{dayOfWeek}
AND l.year = #{year}
AND l.semester = #{semester}
AND l.status != 'rejected'
AND (#{startPeriod} BETWEEN ls.start_period AND ls.end_period
    OR #{endPeriod} BETWEEN ls.start_period AND ls.end_period
    OR ls.start_period BETWEEN #{startPeriod} AND #{endPeriod})

        AND ls.lecture_id != #{lectureId} 

    ) AS roomConflict,

(SELECT COUNT(*) FROM lecture_schedule ls
JOIN lecture l ON ls.lecture_id = l.lecture_id
WHERE l.member_id = #{loginUserId}
AND ls.day_of_week = #{dayOfWeek}
AND l.year = #{year}
AND l.semester = #{semester}
AND l.status != 'rejected'
AND (#{startPeriod} BETWEEN ls.start_period AND ls.end_period
    OR #{endPeriod} BETWEEN ls.start_period AND ls.end_period
    OR ls.start_period BETWEEN #{startPeriod} AND #{endPeriod})

    AND ls.lecture_id != #{lectureId}

) AS professorConflict,

(SELECT CASE WHEN capacity < #{maxStd} THEN 1 ELSE 0 END
FROM lecture_room
WHERE room_number = #{roomNumber} LIMIT 1
) AS capacityOver

SELECT l.status, l.member_id, l.lecture_id AS lectureId, l.type AS lectureType, l.name AS lectureName, m.name AS proName, l.credit, l.semester, l.year, ls.day_of_week as dayOfWeek, ls.end_period AS endPeriod, ls.start_period AS startPeriod, lr.building, lr.room_number as roomNumber, l.academic_year AS academicYear, l.max_std AS maxStd, l.is_open FROM lecture l JOIN member m ON l.member_id = m.member_id LEFT JOIN lecture_schedule ls ON l.lecture_id = ls.lecture_id LEFT JOIN lecture_room lr ON ls.room_id = lr.room_id
WHERE l.member_id = #{loginUserId}
ORDER BY l.lecture_id DESC

SELECT ma.`name` AS majorName, m.`code` AS studentCode, m.`name` AS studentName, s.academic_year AS academicYear, c.grade_letter AS gradeLetter, c.lecture_id AS lectureId FROM course c JOIN student s ON c.member_id = s.member_id JOIN major ma ON s.major_id = ma.major_id JOIN member m ON s.member_id = m.member_id WHERE c.lecture_id = #{req.lectureId}
AND c.lecture_id IN ( SELECT lecture_id FROM lecture WHERE member_id = #{loginUserId} )
ORDER BY m.`name` ASC

mapper.update:
UPDATE lecture
SET status = #{status}
WHERE lecture_id = #{lectureId}

mapper.delete:
DELETE FROM lecture
WHERE lecture_id = #{lectureId}
AND member_id = #{loginUserId}
